#include "controller.h"

#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    if (controller == 0) {
        return;
    }
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    memset(controller, 0, sizeof(controller_t));
    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static bool is_sensor_stale(controller_t *controller, uint32_t now_ms)
{
    if (controller == 0) {
        return true;
    }
    return ((now_ms - controller->last_temperature_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) ||
           ((now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS);
}

static void update_heater_state(controller_t *controller, bool heater_should_be_on)
{
    if (controller == 0) {
        return;
    }
    controller->heater_on = heater_should_be_on;
}

static void update_inlet_state(controller_t *controller, bool inlet_should_be_open)
{
    if (controller == 0) {
        return;
    }
    controller->inlet_open = inlet_should_be_open;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for sensor timeout or invalid input */
    if ((input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) ||
        (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) ||
        (input.kind == CONTROLLER_INPUT_INVALID_LEVEL)) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
    }

    /* Process valid inputs */
    switch (input.kind) {
    case CONTROLLER_INPUT_NONE:
        /* No new input - check for staleness */
        if (is_sensor_stale(controller, input.now_ms)) {
            controller_set_safe_idle(controller);
            output.timed_out = true;
        }
        break;

    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        /* Temperature update doesn't change state by itself */
        break;

    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        /* Level update may trigger state changes */
        break;
    }

    /* Apply staleness check after processing valid inputs */
    if (is_sensor_stale(controller, input.now_ms)) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
    }

    /* Determine actuator states based on control policy */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        /* Stay in safe all-off state until both sensors seen validly */
        controller_set_safe_idle(controller);
    } else if (controller->last_level < 55) {
        /* Heater must be off when level is too low */
        update_inlet_state(controller, controller->last_level < 60);
        update_heater_state(controller, false);
        if (controller->last_level < 60) {
            controller->state = CONTROLLER_STATE_FILLING;
        } else {
            controller->state = CONTROLLER_STATE_HOLDING;
        }
    } else {
        /* Level is safe (>= 55), apply heating logic */
        int level = controller->last_level;
        int temp = controller->last_temperature_c;

        if (level < 60) {
            /* Fill the tank */
            update_inlet_state(controller, true);
            update_heater_state(controller, false);
            controller->state = CONTROLLER_STATE_FILLING;
        } else if (level > 75) {
            /* Close inlet when level is high */
            update_inlet_state(controller, false);
            update_heater_state(controller, false);
            controller->state = CONTROLLER_STATE_HOLDING;
        } else {
            /* Level is in safe band [60, 75], apply heating logic */
            if (temp < 45) {
                /* Low temperature: close inlet and turn on heater */
                update_inlet_state(controller, false);
                update_heater_state(controller, true);
                controller->state = CONTROLLER_STATE_HEATING;
            } else if ((temp >= 45) && (temp < 47)) {
                /* Temperature in [45, 47): close inlet, hold previous heater state */
                update_inlet_state(controller, false);
                /* Heater state is already set correctly from previous step */
                controller->state = CONTROLLER_STATE_HOLDING;
            } else if ((temp >= 47) && (temp <= 48)) {
                /* Temperature in [47, 48]: check if rising */
                bool temp_rising = false;
                if (controller->previous_temperature_c < controller->last_temperature_c) {
                    temp_rising = true;
                }

                if (temp_rising) {
                    /* Early heater off when temperature is rising */
                    update_inlet_state(controller, false);
                    update_heater_state(controller, false);
                    controller->state = CONTROLLER_STATE_HOLDING;
                } else {
                    /* Hold previous safe heater state (heater may be on or off) */
                    controller->state = CONTROLLER_STATE_HOLDING;
                }
            } else if (temp > 48) {
                /* Temperature above 48: close inlet and turn off heater */
                update_inlet_state(controller, false);
                update_heater_state(controller, false);
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* temp == 47 exactly: hold previous safe heater state */
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        }
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

